// generar_238_analisis_ilustraciones.js
// CHIQUI Entre Señales — Ilustraciones de Chiqui en Análisis
//
// Reemplaza emojis/stickers por ilustraciones de Chiqui en 3 encabezados:
// 1) 🤖 Resumen del período → Chiqui IA (nueva ilustración
//    chiqui_ia.png) — refuerza que es la sección inteligente.
// 2) Lo observado este mes → Chiqui con lupa (chiqui_lupa.png, ya
//    existente), quitando el sticker de perro que duplicaba con el
//    gráfico. También se quitó el 📊 redundante del título.
// 3) Rutinas de cuidado → Chiqui análisis (chiqui_analisis.png, ya
//    existente), en vez del emoji de reversa 🔁.
//
// Escribe app/analisis/page.tsx + public/chiqui/chiqui_ia.png.
// No hay SQL.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_238_analisis_ilustraciones.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/analisis/page.tsx",
    base64: "",
    png: false
  },
  {
    ruta: "public/chiqui/chiqui_ia.png",
    base64: "",
    png: true
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64')
    if (a.png) {
      fs2.writeFileSync(rutaCompleta, contenido)
    } else {
      fs2.writeFileSync(rutaCompleta, contenido.toString('utf8'), 'utf8')
    }
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 1 archivo de código + 1 imagen escritos correctamente.')
  console.log('No hay SQL esta vez. Puedes hacer git add / commit / push directo.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
